import React, { useEffect } from 'react';
import {
  useSignalREvent,
  HubEvent,
  conversationEndpoint,
  subscriptionService,
  markConversationReadLocal,
  updateConversationFromMessage,
  fetchUnreadMessageCount,
  incrementUnreadMessages,
  signalRService,
  hasValidAuthToken,
} from '@linm-soft/common-components';
import { messageStore } from '../store/store';

function isViewingEntity(entityId: string, entityType: string): boolean {
  const p = window.location.pathname;
  return (
    p === `/messages/${entityType}/${entityId}` ||
    p.startsWith(`/tickets/${entityId}`) ||
    p.startsWith(`/tasks/${entityId}`) ||
    p.startsWith(`/medical-incidents/${entityId}`)
  );
}

/** SignalR + badge sync — owned exclusively by @linm/message lifecycle. */
export const MessageLifecycleBridge: React.FC = () => {
  useEffect(() => {
    if (hasValidAuthToken()) {
      messageStore.dispatch(fetchUnreadMessageCount());
    }

    const onAuth = (e: Event) => {
      const { token } = (e as CustomEvent<{ token: string | null }>).detail;
      if (token) messageStore.dispatch(fetchUnreadMessageCount());
    };
    window.addEventListener('linm:auth:token-changed', onAuth);

    const onVisibility = () => {
      if (document.visibilityState === 'visible' && hasValidAuthToken()) {
        messageStore.dispatch(fetchUnreadMessageCount());
      }
    };
    document.addEventListener('visibilitychange', onVisibility);

    const offReconnect = signalRService.onReconnected(() => {
      messageStore.dispatch(fetchUnreadMessageCount());
    });

    return () => {
      window.removeEventListener('linm:auth:token-changed', onAuth);
      document.removeEventListener('visibilitychange', onVisibility);
      offReconnect?.();
    };
  }, []);

  useSignalREvent(HubEvent.ReceiveNotification, (notif) => {
    if (notif.type !== 'NEW_MESSAGE') return;

    const entityId = notif.entityId;
    const entityType = notif.entityType as 'ticket' | 'task' | 'incident' | undefined;
    if (!entityId || !entityType) return;

    const isPageActive =
      isViewingEntity(entityId, entityType) &&
      document.visibilityState === 'visible' &&
      document.hasFocus();

    if (isPageActive) {
      messageStore.dispatch(markConversationReadLocal(entityId));
      conversationEndpoint.markConversationRead(entityType, entityId).catch(() => {});
    } else {
      messageStore.dispatch(incrementUnreadMessages());
    }

    subscriptionService.registerSubscription(entityType, entityId).catch(() => {});
    messageStore.dispatch(
      updateConversationFromMessage({
        entityId,
        entityType,
        lastMessage: {
          content: notif.message,
          userName: '',
          createdAt: notif.createdAt,
        },
      }),
    );
  });

  useSignalREvent(HubEvent.NewMessage, () => {
    messageStore.dispatch(incrementUnreadMessages());
  });

  return null;
};
