import React from 'react';
import { createRoot } from 'react-dom/client';
import singleSpaReact from 'single-spa-react';
import { MessageCenter, type MessageCenterProps } from '@linm-soft/common-components';
import { MessageParcelShell } from '../components/MessageParcelShell';

const MessageCenterWithProvider: React.FC<MessageCenterProps> = (props) => (
  <MessageParcelShell>
    <MessageCenter {...props} />
  </MessageParcelShell>
);

export const MessageCenterParcel = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: MessageCenterWithProvider,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});
