import React, { useEffect } from 'react';
import {
  ChatPanel,
  conversationEndpoint,
  useConversations,
  clearUnreadMessages,
  markConversationReadLocal,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { ConversationList } from './components/ConversationList/ConversationList';
import styles from './MessagesInboxPage.module.css';

export interface MessagesInboxPageProps {
  entityType?: string;
  entityId?: string;
  onNavigate: (path: string) => void;
}

/**
 * Full-page messages inbox — SSOT in @linm/message.
 * Mounted via MessagesInboxParcel; route params passed as props from host MFE.
 */
export const MessagesInboxPage: React.FC<MessagesInboxPageProps> = ({
  entityType,
  entityId,
  onNavigate,
}) => {
  const dispatch = useAppDispatch();

  const {
    conversations,
    loading,
    hasMore,
    selectedEntityId,
    selectedEntityType,
    selectedConversation,
    reload,
    loadMore,
    selectConv,
    clearSelection,
  } = useConversations();

  useEffect(() => {
    if (
      entityId &&
      entityType &&
      (entityType === 'ticket' || entityType === 'task' || entityType === 'incident')
    ) {
      selectConv(entityId, entityType);
    }
  }, [entityId, entityType, selectConv]);

  useEffect(() => {
    dispatch(clearUnreadMessages());
  }, [dispatch]);

  const handleSelect = (id: string, type: 'ticket' | 'task' | 'incident') => {
    selectConv(id, type);
    onNavigate(`/messages/${type}/${id}`);
    dispatch(markConversationReadLocal(id));
    conversationEndpoint.markConversationRead(type, id).catch(() => {});
  };

  const handleBack = () => {
    clearSelection();
    onNavigate('/messages');
  };

  const showList = !selectedEntityId;
  const showChat = !!selectedEntityId;

  return (
    <div className={styles.page}>
      <aside className={`${styles.sidebar} ${showChat ? styles.hiddenMobile : ''}`}>
        <div className={styles.sidebarHeader}>
          <h2 className={styles.sidebarTitle}>
            <i className="fas fa-comments" /> Tin nhắn
          </h2>
          <button className={styles.reloadBtn} onClick={reload} title="Tải lại" type="button">
            <i className="fas fa-sync-alt" />
          </button>
        </div>
        <ConversationList
          conversations={conversations}
          selectedEntityId={selectedEntityId}
          selectedEntityType={selectedEntityType}
          loading={loading}
          hasMore={hasMore}
          onSelect={handleSelect}
          onLoadMore={loadMore}
          onReload={reload}
        />
      </aside>

      <main className={`${styles.chatArea} ${showList ? styles.hiddenMobile : ''}`}>
        {selectedConversation ? (
          <>
            <button className={styles.backBtn} onClick={handleBack} type="button">
              <i className="fas fa-arrow-left" /> Danh sách
            </button>
            <ChatPanel conversation={selectedConversation} />
          </>
        ) : (
          <div className={styles.emptyState}>
            <i className="fas fa-comments" />
            <p>Chọn một cuộc hội thoại để bắt đầu</p>
          </div>
        )}
      </main>
    </div>
  );
};
