import React, { useEffect } from 'react';
import { Provider, useDispatch } from 'react-redux';
import { fetchUnreadMessageCount, signalRService } from '@linm-soft/common-components';
import { messageStore } from '../store/store';
import type { MessageDispatch } from '../store/store';

const MessageParcelEffects: React.FC = () => {
  const dispatch = useDispatch<MessageDispatch>();

  useEffect(() => {
    dispatch(fetchUnreadMessageCount());
  }, [dispatch]);

  useEffect(() => {
    const handler = () => {
      if (document.visibilityState === 'visible') dispatch(fetchUnreadMessageCount());
    };
    document.addEventListener('visibilitychange', handler);
    return () => document.removeEventListener('visibilitychange', handler);
  }, [dispatch]);

  useEffect(() => signalRService.onReconnected(() => dispatch(fetchUnreadMessageCount())), [dispatch]);

  return null;
};

export const MessageParcelShell: React.FC<{ children: React.ReactNode }> = ({ children }) => (
  <Provider store={messageStore}>
    <MessageParcelEffects />
    {children}
  </Provider>
);
