/**
 * @linm/message — message inbox SSOT.
 *
 * Lifecycle owns SignalR message side-effects (NEW_MESSAGE → messagesInbox store).
 * SignalR connection is owned by @linm/notification — do NOT call signalRService.start() here.
 *
 * Parcels: MessageCenterParcel (Topbar), MessagesInboxParcel (/messages page).
 */
import React from 'react';
import { createRoot } from 'react-dom/client';
import { Provider } from 'react-redux';
import singleSpaReact from 'single-spa-react';
import { MessageLifecycleBridge } from './lifecycle/MessageLifecycleBridge';
import { messageStore } from './store/store';
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const MessageLifecycle: React.ComponentType<any> = () => (
  <Provider store={messageStore}>
    <MessageLifecycleBridge />
  </Provider>
);

const lifecycles = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: MessageLifecycle,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});

export const bootstrap = lifecycles.bootstrap;
export const mount = lifecycles.mount;
export const unmount = lifecycles.unmount;

export { MessageCenterParcel } from './parcels/MessageCenterParcel';
export { MessagesInboxParcel } from './parcels/MessagesInboxParcel';
