import { configureStore } from '@reduxjs/toolkit';
import { authReducer, messagesInboxReducer } from '@linm-soft/common-components';

export const messageStore = configureStore({
  reducer: {
    auth: authReducer,           // needed by ChatPanel (s.auth.user)
    messagesInbox: messagesInboxReducer,
  },
  devTools: process.env.NODE_ENV !== 'production',
});

export type MessageRootState = ReturnType<typeof messageStore.getState>;
export type MessageDispatch = typeof messageStore.dispatch;
