import React from 'react';
import { createRoot } from 'react-dom/client';
import singleSpaReact from 'single-spa-react';
import { MessageParcelShell } from '../components/MessageParcelShell';
import { MessagesInboxPage, type MessagesInboxPageProps } from '../pages/MessagesInboxPage/MessagesInboxPage';

const MessagesInboxWithProvider: React.FC<MessagesInboxPageProps> = (props) => (
  <MessageParcelShell>
    <MessagesInboxPage {...props} />
  </MessageParcelShell>
);

export const MessagesInboxParcel = singleSpaReact({
  React,
  ReactDOMClient: { createRoot },
  rootComponent: MessagesInboxWithProvider,
  renderType: 'createRoot',
  errorBoundary(error) { throw error; },
});
