import React from 'react';
import type { ConversationSummary } from '@linm-soft/common-components';
import styles from './ConversationList.module.css';

function relativeTime(iso: string): string {
  const diff = Date.now() - new Date(iso).getTime();
  const mins = Math.floor(diff / 60_000);
  const hours = Math.floor(diff / 3_600_000);
  const days = Math.floor(diff / 86_400_000);
  if (mins < 1) return 'Vừa xong';
  if (mins < 60) return `${mins} phút`;
  if (hours < 24) return `${hours} giờ`;
  if (days < 7) return `${days} ngày`;
  return new Date(iso).toLocaleDateString('vi-VN');
}

function entityIcon(type: string): string {
  if (type === 'ticket') return 'fas fa-ticket-alt';
  if (type === 'incident') return 'fas fa-exclamation-triangle';
  return 'fas fa-tasks';
}

function entityColor(type: string): string {
  if (type === 'ticket') return styles.ticketIcon;
  if (type === 'incident') return styles.incidentIcon;
  return styles.taskIcon;
}

interface ConversationItemProps {
  conversation: ConversationSummary;
  isSelected: boolean;
  onSelect: (entityId: string, entityType: 'ticket' | 'task' | 'incident') => void;
}

const ConversationItem: React.FC<ConversationItemProps> = ({
  conversation,
  isSelected,
  onSelect,
}) => {
  const { entityId, entityType, entityIdCode, entityTitle, entityStatus, lastMessage } = conversation;

  return (
    <button
      className={`${styles.item} ${isSelected ? styles.selected : ''}`}
      onClick={() => onSelect(entityId, entityType as 'ticket' | 'task' | 'incident')}
      aria-selected={isSelected}
    >
      <div className={`${styles.itemIcon} ${entityColor(entityType)}`}>
        <i className={entityIcon(entityType)} />
      </div>
      <div className={styles.itemContent}>
        <div className={styles.itemHeader}>
          <span className={styles.idCode}>{entityIdCode}</span>
          <div className={styles.headerRight}>
            {lastMessage && <span className={styles.time}>{relativeTime(lastMessage.createdAt)}</span>}
            {conversation.unreadCount > 0 && (
              <span className={styles.unreadBadge}>
                {conversation.unreadCount > 99 ? '99+' : conversation.unreadCount}
              </span>
            )}
          </div>
        </div>
        <div className={styles.title}>{entityTitle}</div>
        {lastMessage && (
          <div className={styles.preview}>
            <span className={styles.previewAuthor}>{lastMessage.userName}:</span>{' '}
            <span className={styles.previewContent}>{lastMessage.content}</span>
          </div>
        )}
        <div className={styles.meta}>
          <span className={styles.status}>{entityStatus}</span>
          <span className={styles.msgCount}>
            <i className="fas fa-comment" /> {conversation.totalMessageCount}
          </span>
        </div>
      </div>
    </button>
  );
};

export interface ConversationListProps {
  conversations: ConversationSummary[];
  selectedEntityId: string | null;
  selectedEntityType: string | null;
  loading: boolean;
  hasMore: boolean;
  onSelect: (entityId: string, entityType: 'ticket' | 'task' | 'incident') => void;
  onLoadMore: () => void;
  onReload: () => void;
}

export const ConversationList: React.FC<ConversationListProps> = ({
  conversations,
  selectedEntityId,
  selectedEntityType,
  loading,
  hasMore,
  onSelect,
  onLoadMore,
  onReload,
}) => {
  if (loading && conversations.length === 0) {
    return (
      <div className={styles.listWrap}>
        <div className={styles.empty}>
          <i className="fas fa-spinner fa-spin" />
          <span>Đang tải...</span>
        </div>
      </div>
    );
  }

  if (!loading && conversations.length === 0) {
    return (
      <div className={styles.listWrap}>
        <div className={styles.empty}>
          <i className="fas fa-comments" />
          <p>Chưa có cuộc hội thoại nào</p>
          <button className={styles.reloadBtn} onClick={onReload}>
            <i className="fas fa-sync-alt" /> Tải lại
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.listWrap}>
      <div className={styles.list}>
        {conversations.map((conv) => (
          <ConversationItem
            key={`${conv.entityType}-${conv.entityId}`}
            conversation={conv}
            isSelected={conv.entityId === selectedEntityId && conv.entityType === selectedEntityType}
            onSelect={onSelect}
          />
        ))}
        {hasMore && (
          <button className={styles.loadMoreBtn} onClick={onLoadMore}>
            <i className="fas fa-chevron-down" /> Tải thêm
          </button>
        )}
      </div>
    </div>
  );
};
